import { Schema } from "effect"

// Branded IDs
export const TxHash = Schema.String.pipe(Schema.brand("@Falcon/TxHash"))
export type TxHash = Schema.Schema.Type<typeof TxHash>

export const ContractAddress = Schema.String.pipe(Schema.brand("@Falcon/ContractAddress"))
export type ContractAddress = Schema.Schema.Type<typeof ContractAddress>

// Domain types
export interface FalconKeypair {
  readonly secretKey: Uint8Array
  readonly verifyingKey: Uint8Array
  readonly publicKeyNtt: Int32Array // h polynomial, 512 coefficients
}

export interface FalconSignatureResult {
  readonly signature: Uint8Array
  readonly salt: Uint8Array
}

export interface PackedPublicKey {
  readonly slots: ReadonlyArray<string> // 29 hex strings (felt252)
}

export interface DeployPrecompute {
  readonly address: ContractAddress
  readonly salt: string
  readonly constructorCalldata: Array<string>
}

export type VerificationStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "signing" }
  | { step: "creating-hint" }
  | { step: "packing" }
  | { step: "verifying"; substep: string }
  | { step: "complete"; valid: boolean; durationMs: number }
  | { step: "error"; message: string }

export interface PipelineStep {
  readonly id: string
  readonly name: string
  readonly description: string
  readonly input: string
  readonly output: string
  readonly stepCount: number
  readonly status: "pending" | "active" | "complete"
}

/**
 * Tests for verify-playground Schema.TaggedError classes.
 *
 * Coverage requirements:
 * - Every Schema.TaggedError must be constructable and matchable
 * - _tag must equal the class name string
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Cause } from "effect"
import {
  WasmLoadError,
  KeygenError,
  SigningError,
  VerificationError,
  HintGenerationError,
  PackingError,
} from "../../services/errors"

describe("WasmLoadError", () => {
  it("is constructable with a message", () => {
    const err = new WasmLoadError({ message: "failed to load wasm" })
    expect(err.message).toBe("failed to load wasm")
    expect(err._tag).toBe("WasmLoadError")
  })

  it("can be used as Effect failure and matched by _tag", async () => {
    const effect = Effect.fail(
      new WasmLoadError({ message: "module missing" }),
    )
    const exit = await Effect.runPromiseExit(effect)
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(err._tag).toBe("Some")
      // @ts-expect-error — Option.Some wraps the error
      expect(err.value._tag).toBe("WasmLoadError")
      // @ts-expect-error
      expect(err.value.message).toBe("module missing")
    }
  })

  it("can be caught with catchTag", async () => {
    let caught = false
    const effect = Effect.fail(
      new WasmLoadError({ message: "oops" }),
    ).pipe(
      Effect.catchTag("WasmLoadError", () => {
        caught = true
        return Effect.succeed("recovered")
      }),
    )
    const result = await Effect.runPromise(effect)
    expect(result).toBe("recovered")
    expect(caught).toBe(true)
  })
})

describe("KeygenError", () => {
  it("is constructable with a message", () => {
    const err = new KeygenError({ message: "keygen failed" })
    expect(err.message).toBe("keygen failed")
    expect(err._tag).toBe("KeygenError")
  })

  it("roundtrips through Effect failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new KeygenError({ message: "seed error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      // @ts-expect-error
      expect(err.value._tag).toBe("KeygenError")
    }
  })
})

describe("SigningError", () => {
  it("is constructable with a message", () => {
    const err = new SigningError({ message: "signing failed" })
    expect(err.message).toBe("signing failed")
    expect(err._tag).toBe("SigningError")
  })

  it("roundtrips through Effect failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new SigningError({ message: "sig err" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

describe("VerificationError", () => {
  it("is constructable with message and step", () => {
    const err = new VerificationError({
      message: "norm check failed",
      step: "norm-check",
    })
    expect(err.message).toBe("norm check failed")
    expect(err.step).toBe("norm-check")
    expect(err._tag).toBe("VerificationError")
  })

  it("can be caught by _tag", async () => {
    let caughtStep = ""
    await Effect.runPromise(
      Effect.fail(
        new VerificationError({ message: "bad sig", step: "verify" }),
      ).pipe(
        Effect.catchTag("VerificationError", (e) => {
          caughtStep = e.step
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtStep).toBe("verify")
  })
})

describe("HintGenerationError", () => {
  it("is constructable with a message", () => {
    const err = new HintGenerationError({ message: "hint failed" })
    expect(err.message).toBe("hint failed")
    expect(err._tag).toBe("HintGenerationError")
  })

  it("fails the effect on failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new HintGenerationError({ message: "ntt error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    expect(Exit.isSuccess(exit)).toBe(false)
  })
})

describe("PackingError", () => {
  it("is constructable with a message", () => {
    const err = new PackingError({ message: "pack failed" })
    expect(err.message).toBe("pack failed")
    expect(err._tag).toBe("PackingError")
  })

  it("fails the effect on failure", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new PackingError({ message: "slots error" })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

/**
 * Tests for FalconService — verify-playground category.
 *
 * Coverage requirements:
 * - Every Effect service method must have at least one success and one failure test
 * - WasmRuntime is mocked via Layer.succeed so no real WASM is needed
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Layer } from "effect"
import { WasmRuntime } from "../../services/WasmRuntime"
import { FalconService } from "../../services/FalconService"
import type { WasmModule } from "../../services/WasmRuntime"

// ---------------------------------------------------------------------------
// Mock WASM module factories
// ---------------------------------------------------------------------------

const makeSuccessWasm = (): WasmModule => ({
  keygen: (_seed) => ({
    sk: new Uint8Array(1281).fill(1),
    vk: new Uint8Array(897).fill(2),
  }),
  sign: (_sk, _msg, _salt) => ({
    signature: new Uint8Array(666).fill(3),
    salt: new Uint8Array(40).fill(4),
  }),
  verify: (_vk, _msg, _sig) => true,
  create_verification_hint: (_s1, _pkNtt) =>
    new Uint16Array(512).fill(0),
  pack_public_key_wasm: (_pkNtt) =>
    Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  public_key_length: () => 897,
  salt_length: () => 40,
})

const makeFailingWasm = (): WasmModule => ({
  keygen: () => {
    throw new Error("keygen failed in WASM")
  },
  sign: () => {
    throw new Error("signing failed in WASM")
  },
  verify: () => {
    throw new Error("verification failed in WASM")
  },
  create_verification_hint: () => {
    throw new Error("hint generation failed in WASM")
  },
  pack_public_key_wasm: () => {
    throw new Error("packing failed in WASM")
  },
  public_key_length: () => 897,
  salt_length: () => 40,
})

// Layer helpers
const makeSuccessLayer = () =>
  Layer.succeed(WasmRuntime, makeSuccessWasm())

const makeFailingLayer = () =>
  Layer.succeed(WasmRuntime, makeFailingWasm())

/** Run an effect provided with a specific WasmRuntime mock */
async function runWith<A, E>(
  effect: Effect.Effect<A, E, FalconService>,
  wasmLayer: Layer.Layer<WasmRuntime>,
): Promise<Exit.Exit<A, E>> {
  // FalconService.Default provides FalconService using its registered dependencies.
  // We override the WasmRuntime dependency via Layer.provide.
  const serviceLayer = FalconService.Default.pipe(
    Layer.provide(wasmLayer),
  )
  return Effect.runPromiseExit(effect.pipe(Effect.provide(serviceLayer)))
}

// ---------------------------------------------------------------------------
// generateKeypair
// ---------------------------------------------------------------------------

describe("FalconService.generateKeypair", () => {
  it("succeeds and returns a FalconKeypair", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.secretKey).toBeInstanceOf(Uint8Array)
      expect(exit.value.verifyingKey).toBeInstanceOf(Uint8Array)
      expect(exit.value.publicKeyNtt).toBeInstanceOf(Int32Array)
    }
  })

  it("succeeds without explicit seed (uses crypto.getRandomValues)", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
  })

  it("fails with KeygenError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.generateKeypair(new Uint8Array(32)),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = exit.cause
      // The error should be a KeygenError
      expect(JSON.stringify(err)).toContain("KeygenError")
    }
  })
})

// ---------------------------------------------------------------------------
// sign
// ---------------------------------------------------------------------------

describe("FalconService.sign", () => {
  const sk = new Uint8Array(1281).fill(1)
  const msg = new TextEncoder().encode("Hello, Falcon!")

  it("succeeds and returns a FalconSignatureResult", async () => {
    const exit = await runWith(
      FalconService.sign(sk, msg),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.signature).toBeInstanceOf(Uint8Array)
      expect(exit.value.salt).toBeInstanceOf(Uint8Array)
    }
  })

  it("fails with SigningError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.sign(sk, msg),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("SigningError")
    }
  })
})

// ---------------------------------------------------------------------------
// verify
// ---------------------------------------------------------------------------

describe("FalconService.verify", () => {
  const vk = new Uint8Array(897).fill(2)
  const msg = new TextEncoder().encode("Hello, Falcon!")
  const sig = new Uint8Array(666).fill(3)

  it("succeeds and returns true for valid signature", async () => {
    const exit = await runWith(
      FalconService.verify(vk, msg, sig),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(true)
    }
  })

  it("succeeds and returns false when mock wasm returns false", async () => {
    const falseWasm: WasmModule = {
      ...makeSuccessWasm(),
      verify: () => false,
    }
    const exit = await runWith(
      FalconService.verify(vk, msg, sig),
      Layer.succeed(WasmRuntime, falseWasm),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(false)
    }
  })

  it("fails with VerificationError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.verify(vk, msg, sig),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("VerificationError")
    }
  })
})

// ---------------------------------------------------------------------------
// createHint
// ---------------------------------------------------------------------------

describe("FalconService.createHint", () => {
  const s1 = new Int32Array(512).fill(1)
  const pkNtt = new Int32Array(512).fill(2)

  it("succeeds and returns a Uint16Array hint", async () => {
    const exit = await runWith(
      FalconService.createHint(s1, pkNtt),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBeInstanceOf(Uint16Array)
      expect(exit.value.length).toBe(512)
    }
  })

  it("fails with HintGenerationError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.createHint(s1, pkNtt),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("HintGenerationError")
    }
  })
})

// ---------------------------------------------------------------------------
// packPublicKey
// ---------------------------------------------------------------------------

describe("FalconService.packPublicKey", () => {
  const pkNtt = new Uint16Array(512).fill(100)

  it("succeeds and returns 29 felt252 hex slots", async () => {
    const exit = await runWith(
      FalconService.packPublicKey(pkNtt),
      makeSuccessLayer(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.slots.length).toBe(29)
      for (const slot of exit.value.slots) {
        expect(slot).toMatch(/^0x/)
      }
    }
  })

  it("fails with PackingError when WASM throws", async () => {
    const exit = await runWith(
      FalconService.packPublicKey(pkNtt),
      makeFailingLayer(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("PackingError")
    }
  })
})

/**
 * Type declarations for the dynamically-imported Falcon-512 WASM module.
 *
 * This module is served from the Next.js public directory at /wasm/falcon_rs.js
 * and built with wasm-pack from falcon-rs/. The runtime guard `isValidWasmModule`
 * in WasmRuntime.ts provides additional safety checks at load time.
 */
declare module "/wasm/falcon_rs.js" {
  /** Generate a new Falcon-512 keypair from a seed. */
  export function keygen(seed: Uint8Array): unknown

  /** Get the public key length in bytes. */
  export function public_key_length(): number

  /** Get the salt length in bytes. */
  export function salt_length(): number

  /** Sign a message with a Falcon-512 secret key. */
  export function sign(
    skBytes: Uint8Array,
    message: Uint8Array,
    salt: Uint8Array,
  ): unknown

  /** Verify a Falcon-512 signature. */
  export function verify(
    vkBytes: Uint8Array,
    message: Uint8Array,
    signature: Uint8Array,
  ): boolean

  /** Create a verification hint for hint-based verification. */
  export function create_verification_hint(
    s1: Int32Array,
    pkNtt: Int32Array,
  ): Uint16Array

  /** Pack a public key in Zq (NTT) form into base-Q packed strings. */
  export function pack_public_key_wasm(pkNtt: Uint16Array): string[]

  /** wasm-pack default export: initialises and instantiates the WASM binary. */
  export default function init(): Promise<unknown>
}

import { Effect } from "effect"
import { WasmRuntime } from "./WasmRuntime"
import {
  KeygenError,
  SigningError,
  HintGenerationError,
  PackingError,
  VerificationError,
} from "./errors"
import type {
  FalconKeypair,
  FalconSignatureResult,
  PackedPublicKey,
} from "./types"

export class FalconService extends Effect.Service<FalconService>()(
  "FalconService",
  {
    accessors: true,
    // No pre-bundled dependencies: callers must provide WasmRuntime via Layer.
    // This enables unit tests to inject a mock WasmRuntime without the live
    // loader trying to fetch /wasm/falcon_rs.js at import time.
    effect: Effect.gen(function* () {
      const wasm = yield* WasmRuntime

      const generateKeypair = Effect.fn("Falcon.generateKeypair")(
        function* (seed?: Uint8Array) {
          const s =
            seed ?? crypto.getRandomValues(new Uint8Array(32))
          const result = yield* Effect.try({
            try: () => wasm.keygen(s),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          return {
            secretKey: result.sk,
            verifyingKey: result.vk,
            publicKeyNtt: new Int32Array(512),
          } satisfies FalconKeypair
        },
      )

      const sign = Effect.fn("Falcon.sign")(
        function* (
          secretKey: Uint8Array,
          message: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () =>
              wasm.sign(secretKey, message, new Uint8Array(0)),
            catch: (error) =>
              new SigningError({ message: String(error) }),
          })
        },
      )

      const verify = Effect.fn("Falcon.verify")(
        function* (
          verifyingKey: Uint8Array,
          message: Uint8Array,
          signature: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.verify(verifyingKey, message, signature),
            catch: (error) =>
              new VerificationError({
                message: String(error),
                step: "verify",
              }),
          })
        },
      )

      const createHint = Effect.fn("Falcon.createHint")(
        function* (
          s1: Int32Array,
          pkNtt: Int32Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.create_verification_hint(s1, pkNtt),
            catch: (error) =>
              new HintGenerationError({ message: String(error) }),
          })
        },
      )

      const packPublicKey = Effect.fn("Falcon.packPublicKey")(
        function* (
          pkNtt: Uint16Array,
        ) {
          const slots = yield* Effect.try({
            try: () => wasm.pack_public_key_wasm(pkNtt),
            catch: (error) =>
              new PackingError({ message: String(error) }),
          })
          return { slots } satisfies PackedPublicKey
        },
      )

      return {
        generateKeypair,
